codeComparison.old:
/* Images are inline by default - gap below! */
.image-container img {
  max-width: 100%;
}

codeComparison.new:
/* Fix: make image block to remove gap */
.image-container img {
  max-width: 100%;
  display: block;
}

/* Buttons side by side with inline-block */
.btn {
  display: inline-block;
  background-color: #007bff;
  color: white;
  padding: 12px 24px;
  border: none;
  border-radius: 4px;
  margin-right: 10px;
}

codeComparison.old:
/* Desktop only — menu always visible */
.nav-links {
  display: flex;
  list-style: none;
}

codeComparison.new:
/* Mobile: slide-in menu */
@media (max-width: 768px) {
  .menu-toggle {
    display: block;
  }

  .nav-links {
    position: fixed;
    top: 70px;
    right: -100%;
    flex-direction: column;
    background-color: #333;
    width: 250px;
    height: calc(100vh - 70px);
    transition: right 0.3s ease;
  }

  .nav-links.active {
    right: 0;
  }
}
